@strawberry.type
class ProductType:
    id: int
    sku: Optional[str]
    name: str
    description: Optional[str]
    price: float

    @strawberry.field
    def seller(self, info: Info) -> Optional[SellerType]:
        db = get_db(info)
        obj: Product = db.get(Product, self.id)
        if not obj or not obj.seller:
            return None
        s = obj.seller
        return SellerType(id=s.id, name=s.name, rating=s.rating)

    @strawberry.field
    def categories(self, info: Info) -> List[CategoryType]:
        db = get_db(info)
        obj: Product = db.get(Product, self.id)
        if not obj:
            return []
        return [CategoryType(id=c.id, name=c.name) for c in obj.categories]

    @strawberry.field
    def images(self, info: Info) -> List[ImageType]:
        db = get_db(info)
        obj: Product = db.get(Product, self.id)
        if not obj:
            return []
        imgs = sorted(obj.images, key=lambda i: (i.sort_order, i.id))
        return [ImageType(id=i.id, url=i.url, alt_text=i.alt_text, sort_order=i.sort_order) for i in imgs]

    @strawberry.field
    def reviews(self, info: Info) -> List[ReviewType]:
        db = get_db(info)
        obj: Product = db.get(Product, self.id)
        if not obj:
            return []
        revs = sorted(obj.reviews, key=lambda r: (r.created_at, r.id), reverse=True)
        return [
            ReviewType(
                id=r.id,
                author=r.author,
                rating=r.rating,
                title=r.title,
                body=r.body,
                created_at=r.created_at.isoformat() if r.created_at else "",
            )
            for r in revs
        ]

@strawberry.input
class ProductFilter:
    ids: Optional[List[int]] = None
    seller_id: Optional[int] = None
    category_id: Optional[int] = None
    min_price: Optional[float] = None
    max_price: Optional[float] = None
    search: Optional[str] = None

@strawberry.type
class Query:
    @strawberry.field
    def product(self, info: Info, id: int) -> Optional[ProductType]:
        db = get_db(info)
        stmt = (
            select(Product)
            .where(Product.id == id)
            .options(
                selectinload(Product.seller),
                selectinload(Product.categories),
                selectinload(Product.images),
                selectinload(Product.reviews),
            )
        )
        obj = db.execute(stmt).scalars().first()
        if not obj:
            return None
        return ProductType(
            id=obj.id,
            sku=obj.sku,
            name=obj.name,
            description=obj.description,
            price=obj.price,
        )

    @strawberry.field
    def products(
        self,
        info: Info,
        filter: Optional[ProductFilter] = None,
        limit: Optional[int] = None,
        offset: Optional[int] = None,
    ) -> List[ProductType]:
        db = get_db(info)
        stmt = select(Product).options(
            selectinload(Product.seller),
            selectinload(Product.categories),
            selectinload(Product.images),
            selectinload(Product.reviews),
        )

        if filter:
            if filter.ids:
                stmt = stmt.where(Product.id.in_(filter.ids))
            if filter.seller_id is not None:
                stmt = stmt.where(Product.seller_id == filter.seller_id)
            if filter.category_id is not None:
                stmt = stmt.join(Product.categories).where(Category.id == filter.category_id)
            if filter.min_price is not None:
                stmt = stmt.where(Product.price >= filter.min_price)
            if filter.max_price is not None:
                stmt = stmt.where(Product.price <= filter.max_price)
            if filter.search:
                like = f"%{filter.search}%"
                stmt = stmt.where((Product.name.ilike(like)) | (Product.description.ilike(like)))

        stmt = stmt.order_by(Product.id.asc())

        if offset is not None:
            stmt = stmt.offset(offset)
        if limit is not None:
            stmt = stmt.limit(limit)

        objs = db.execute(stmt).scalars().unique().all()
        return [
            ProductType(
                id=o.id,
                sku=o.sku,
                name=o.name,
                description=o.description,
                price=o.price,
            )
            for o in objs
        ]

    @strawberry.field
    def sellers(self, info: Info) -> List[SellerType]:
        db = get_db(info)
        objs = db.execute(select(Seller).order_by(Seller.id.asc())).scalars().all()
        return [SellerType(id=o.id, name=o.name, rating=o.rating) for o in objs]

    @strawberry.field
    def categories(self, info: Info) -> List[CategoryType]:
        db = get_db(info)
        objs = db.execute(select(Category).order_by(Category.name.asc())).scalars().all()
        return [CategoryType(id=o.id, name=o.name) for o in objs]

schema = strawberry.Schema(query=Query)

